// Normalize object keys — strips hidden chars (zero-width spaces, NBSP, BOM, etc.)
function cleanKeys(obj) {
  const clean = {};
  for (const key of Object.keys(obj)) {
    const normalKey = key.replace(/[\s\u00A0\u200B\u200C\u200D\uFEFF]+/g, '_').replace(/^_+|_+$/g, '').toLowerCase();
    clean[normalKey] = obj[key];
  }
  return clean;
}

// Load excluded companies from sheet (specific firm + enterprise names)
const excludedCompanies = $('Read Excluded Companies').all()
  .filter(r => r.json.company_name)
  .map(r => ({
    name: (r.json.company_name || '').toLowerCase().trim(),
    type: (r.json.type || 'excluded').toLowerCase().trim()
  }));

const combos = [];

for (const item of $input.all()) {
  const row = cleanKeys(item.json);

  const isActive = row.active === true || String(row.active).toLowerCase() === 'true';
  if (!isActive) continue;

  const roles = String(row.role_keywords || '').split(';').map(r => r.trim()).filter(Boolean);
  const locs = String(row.locations || '').split(';').map(l => l.trim()).filter(Boolean);
  const excludedKeywords = String(row.excluded_keywords || '').split(';').map(k => k.trim()).filter(Boolean);

  for (const role of roles) {
    for (const loc of locs) {
      combos.push({
        search_id: row.search_id || '',
        query: role,
        location: loc,
        employment_type: String(row.employment_type || 'FULLTIME').toUpperCase().replace(/\s+/g, ''),
        excluded_keywords: excludedKeywords,
        _excluded_companies: excludedCompanies
      });
    }
  }
}

return combos.map(c => ({ json: c }));

// Generic descriptors — hardcoded, these never need to change
const GENERIC_STAFFING_KEYWORDS = [
  'staffing','recruiting','recruitment','talent acquisition','headhunter',
  'executive search','placement agency','temp agency','contingent workforce',
  'msp','rpo','managed service provider','vendor management','contract staffing',
  'staff augmentation','workforce solutions'
];

const results = [];

for (const item of $input.all()) {
  const job = { ...item.json };
  const checkText = `${job.company_name} ${job.job_description}`.toLowerCase();

  // Sheet-based exclusions — specific company names (staffing firms + enterprises)
  const sheetExclusions = job._excluded_companies || [];

  // 1. Check generic staffing keywords
  const genericMatch = GENERIC_STAFFING_KEYWORDS.find(kw => checkText.includes(kw));

  // 2. Check sheet exclusions
  const sheetMatch = sheetExclusions.find(ex => ex.name && checkText.includes(ex.name));

  if (genericMatch) {
    job.pre_filter_result = 'staffing_firm';
    job.company_classification = 'staffing_firm';
    job.company_classification_reason = `Keyword match: "${genericMatch}"`;
  } else if (sheetMatch) {
    job.pre_filter_result = 'staffing_firm'; // routes to rejected path in Route by Pre-Filter
    job.company_classification = sheetMatch.type === 'enterprise' ? 'excluded_enterprise' : 'staffing_firm';
    job.company_classification_reason = `Sheet exclusion (${sheetMatch.type}): "${sheetMatch.name}"`;
  } else {
    const suspiciousPatterns = /(consulting|solutions|group|partners|services|associates|resources)$/i;
    job.pre_filter_result = suspiciousPatterns.test(job.company_name.trim()) ? 'unclear' : 'likely_direct';
  }

  results.push({ json: job });
}

return results;
